import okhttp3.*
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import android.content.Context
import android.content.SharedPreferences

const val BASE_URL = "https://api.example.com"
const val API_KEY = "YOUR_API_KEY"
const val TOKEN_PREF_FILE = "auth_token_prefs"
const val AUTH_TOKEN_KEY = "auth_token"

val client = OkHttpClient().newBuilder()
    .addInterceptor { chain ->
        val original = chain.request()
        val requestBuilder = original.newBuilder()
            .header("Authorization", "Bearer ${getAuthToken(context)}")
            .header("API-Key", API_KEY)
        val request = requestBuilder.build()
        chain.proceed(request)
    }
    .build()

val retrofit = Retrofit.Builder()
    .baseUrl(BASE_URL)
    .client(client)
    .addConverterFactory(GsonConverterFactory.create())
    .build()

interface UserApiService {
    @GET("users")
    suspend fun getUserProfiles(): List<User>
}

data class User(val id: Int, val name: String, val email: String)

fun Context.getAuthToken(context: Context): String? =
    with(context.getSharedPreferences(TOKEN_PREF_FILE, Context.MODE_PRIVATE)) {
        getString(AUTH_TOKEN_KEY, null)
    }

fun Context.saveAuthToken(token: String) {
    val sharedPref = this.getSharedPreferences(TOKEN_PREF_FILE, Context.MODE_PRIVATE)
    val editor = sharedPref.edit()
    editor.putString(AUTH_TOKEN_KEY, token)
    editor.apply()
}